10	// makePowerCatalog builds a []agentlib.ModelInfo with only the Power field set.
11	// Use this to build test catalogs without pinning model IDs or provider names.
12	func makePowerCatalog(powers ...int) []agentlib.ModelInfo {
13		out := make([]agentlib.ModelInfo, len(powers))
14		for i, p := range powers {
15			out[i] = agentlib.ModelInfo{Power: p}
16		}
17		return out
18	}
