20	func TestTopNPowerThreshold_EmptyCatalog(t *testing.T) {
21		assert.Equal(t, 0, TopNPowerThreshold(nil, 1))
22		assert.Equal(t, 0, TopNPowerThreshold([]agentlib.ModelInfo{}, 1))
23	}
24	
25	func TestTopNPowerThreshold_AllZeroPower(t *testing.T) {
26		// Models with zero power are unrated; catalog effectively empty.
27		assert.Equal(t, 0, TopNPowerThreshold(makePowerCatalog(0, 0), 1))
28	}
29	
30	func TestTopNPowerThreshold_Top1(t *testing.T) {
31		// Distinct levels desc: [9, 8, 7, 5]. Top-1 → 9.
32		assert.Equal(t, 9, TopNPowerThreshold(makePowerCatalog(9, 7, 5, 8), 1))
33	}
34	
35	func TestTopNPowerThreshold_Top2(t *testing.T) {
36		// Distinct levels desc: [9, 8, 7, 5]. Top-2 → 8.
37		assert.Equal(t, 8, TopNPowerThreshold(makePowerCatalog(9, 7, 5, 8), 2))
38	}
39	
40	func TestTopNPowerThreshold_Top3(t *testing.T) {
41		// Distinct levels desc: [9, 8, 7, 5]. Top-3 → 7.
42		assert.Equal(t, 7, TopNPowerThreshold(makePowerCatalog(9, 7, 5, 8), 3))
43	}
44	
45	func TestTopNPowerThreshold_DuplicatePowers(t *testing.T) {
46		// Multiple models at the same power count as one distinct level.
47		models := makePowerCatalog(9, 9, 7, 7)
48		// Distinct: [9, 7]. Top-1 → 9.
49		assert.Equal(t, 9, TopNPowerThreshold(models, 1))
50		// Top-2 → 7 (second distinct level).
51		assert.Equal(t, 7, TopNPowerThreshold(models, 2))
52	}
53	
54	func TestTopNPowerThreshold_NExceedsDistinctLevels(t *testing.T) {
55		// Only 2 distinct levels: n=10 returns the lowest level so the threshold
56		// remains satisfiable — it does not return 0.
57		assert.Equal(t, 7, TopNPowerThreshold(makePowerCatalog(9, 7), 10))
58	}
59	
60	func TestTopNPowerThreshold_StableAcrossOrderChange(t *testing.T) {
61		// Catalog order must not affect the threshold.
62		a := makePowerCatalog(5, 9, 7, 8)
63		b := makePowerCatalog(9, 8, 7, 5)
64		c := makePowerCatalog(7, 5, 9, 8)
65		want := TopNPowerThreshold(a, 1)
66		assert.Equal(t, want, TopNPowerThreshold(b, 1), "order b")
67		assert.Equal(t, want, TopNPowerThreshold(c, 1), "order c")
68		want2 := TopNPowerThreshold(a, 2)
69		assert.Equal(t, want2, TopNPowerThreshold(b, 2), "order b n=2")
70		assert.Equal(t, want2, TopNPowerThreshold(c, 2), "order c n=2")
71	}
72	
73	func TestTopNPowerThreshold_NoBranchingOnModelOrProvider(t *testing.T) {
74		// Identical power values with different IDs and providers must yield the
75		// same threshold — the function must not inspect names.
76		named := []agentlib.ModelInfo{
77			{ID: "claude-opus-4-6", Provider: "anthropic", Power: 9},
78			{ID: "gpt-5.4", Provider: "openai", Power: 7},
79		}
80		anonymous := []agentlib.ModelInfo{
81			{ID: "any-model", Provider: "any-provider", Power: 9},
82			{ID: "other-model", Provider: "other-provider", Power: 7},
83		}
84		assert.Equal(t, TopNPowerThreshold(named, 1), TopNPowerThreshold(anonymous, 1))
85		assert.Equal(t, TopNPowerThreshold(named, 2), TopNPowerThreshold(anonymous, 2))
86	}
