157	// TestExecuteOnService_InvalidPassthroughNotPrevalidated (AC6): DDx must NOT
158	// reject an obviously bogus harness/provider/model before forwarding to the
159	// service. The service is the authoritative validator.
160	func TestExecuteOnService_InvalidPassthroughNotPrevalidated(t *testing.T) {
161		svc := &passthroughTestService{}
162		rcfg := resolvedWithPassthrough("definitely-not-a-real-harness!!!", "bogus-provider", "bogus-model-xyz", 0, 0)
163	
164		_, err := executeOnService(context.Background(), svc, t.TempDir(), rcfg, AgentRunRuntime{
165			Prompt: "hello",
166		})
167		// DDx must not return an error from pre-validation; the service stub
168		// returns success so we expect no error here.
169		if err != nil {
170			t.Errorf("DDx pre-validated passthrough and returned error (must not): %v", err)
171		}
172		if !svc.executeCalled {
173			t.Error("Execute was never called — DDx must forward invalid passthrough to service unchanged")
174		}
175		if svc.lastReq.Harness != "definitely-not-a-real-harness!!!" {
176			t.Errorf("Harness was mutated before forwarding: got %q", svc.lastReq.Harness)
177		}
178		if svc.lastReq.Provider != "bogus-provider" {
179			t.Errorf("Provider was mutated before forwarding: got %q", svc.lastReq.Provider)
180		}
181		if svc.lastReq.Model != "bogus-model-xyz" {
182			t.Errorf("Model was mutated before forwarding: got %q", svc.lastReq.Model)
183		}
184	}
