187	// Provider, and Model in ServiceExecuteRequest come exclusively from the
188	// passthrough envelope, not from ad-hoc rcfg.Harness()/rcfg.Provider() calls.
189	func TestExecuteOnService_PassthroughReachesServiceRequest(t *testing.T) {
