210	// TestClassifyFailureMode_BlockedByPassthroughConstraint (AC7): error strings
211	// that indicate a passthrough+power conflict must classify as
212	// blocked_by_passthrough_constraint, not the generic failure modes.
213	func TestClassifyFailureMode_BlockedByPassthroughConstraint(t *testing.T) {
214		cases := []string{
215			"passthrough constraint unsatisfiable: harness=claude min_power=90",
216			"passthrough constraint: harness pin incompatible with requested min_power",
217			"max_power is less than min_power",
218			"harness cannot satisfy power constraint",
219			"harness pin incompatible with power bounds",
220			"model pin incompatible with power bounds",
221			"provider pin incompatible with power bounds",
222		}
223		for _, msg := range cases {
224			got := ClassifyFailureMode("task_failed", 1, msg)
225			if got != FailureModeBlockedByPassthroughConstraint {
226				t.Errorf("ClassifyFailureMode(%q) = %q, want %q", msg, got, FailureModeBlockedByPassthroughConstraint)
227			}
228		}
229	}
