231	// TestClassifyFailureMode_AgentPowerUnsatisfied (AC7): error strings that
232	// indicate no model meets min_power must classify as agent_power_unsatisfied.
233	func TestClassifyFailureMode_AgentPowerUnsatisfied(t *testing.T) {
234		cases := []string{
235			"agent power unsatisfied: no model meets min_power=80",
236			"no model meets min_power constraint",
237			"no model with power >= 80",
238			"minimum power not achievable",
239			"min_power constraint cannot be satisfied",
240		}
241		for _, msg := range cases {
242			got := ClassifyFailureMode("task_failed", 1, msg)
243			if got != FailureModeAgentPowerUnsatisfied {
244				t.Errorf("ClassifyFailureMode(%q) = %q, want %q", msg, got, FailureModeAgentPowerUnsatisfied)
245			}
246		}
247	}
