249	// TestClassifyFailureMode_PassthroughModesDistinctFromGenericFailure (AC7):
250	// passthrough failure modes are not the same as no_viable_provider, timeout,
251	// auth_error, or unknown — the error must not be misclassified.
252	func TestClassifyFailureMode_PassthroughModesDistinctFromGenericFailure(t *testing.T) {
253		forbiddenModes := []string{
254			FailureModeNoViableProvider,
255			FailureModeTimeout,
256			FailureModeAuthError,
257			FailureModeUnknown,
258		}
259	
260		constraintMsg := "passthrough constraint unsatisfiable: harness=claude"
261		powerMsg := "no model meets min_power=80"
262	
263		for _, forbidden := range forbiddenModes {
264			got := ClassifyFailureMode("task_failed", 1, constraintMsg)
265			if got == forbidden {
266				t.Errorf("passthrough constraint error misclassified as %q", forbidden)
267			}
268			got = ClassifyFailureMode("task_failed", 1, powerMsg)
269			if got == forbidden {
270				t.Errorf("power unsatisfied error misclassified as %q", forbidden)
271			}
272		}
273	}
