307	// TestAppendBeadRoutingEvidence_RecordsPassthroughConstraintsSeparately (AC5):
308	// The routing evidence body must contain requested_harness/provider/model and
309	// requested_min_power/max_power as distinct fields, separate from the
310	// resolved/actual values.
311	func TestAppendBeadRoutingEvidence_RecordsPassthroughConstraintsSeparately(t *testing.T) {
312		app := &stubBeadEventAppenderForPassthrough{}
313		pt := config.AgentPassthrough{
314			Harness:  "claude",
315			Provider: "anthropic",
316			Model:    "claude-opus-4-6",
317		}
318		appendBeadRoutingEvidence(app, "ddx-test-01",
319			"claude", "anthropic", "claude-3-5-sonnet-20241022", // actual/resolved
320			"route-reason", "https://api.anthropic.com",
321			pt, 40, 90, 70)
322	
323		if len(app.events) != 1 {
324			t.Fatalf("expected 1 event, got %d", len(app.events))
325		}
326		evt := app.events[0]
327		if evt.Kind != "routing" {
328			t.Errorf("event kind = %q, want %q", evt.Kind, "routing")
329		}
330	
331		var body map[string]any
332		if err := json.Unmarshal([]byte(evt.Body), &body); err != nil {
333			t.Fatalf("unmarshal routing body: %v", err)
334		}
335	
336		// Actual/resolved values
337		if body["resolved_provider"] != "anthropic" {
338			t.Errorf("resolved_provider = %v, want %q", body["resolved_provider"], "anthropic")
339		}
340		if body["resolved_model"] != "claude-3-5-sonnet-20241022" {
341			t.Errorf("resolved_model = %v, want %q", body["resolved_model"], "claude-3-5-sonnet-20241022")
342		}
343	
344		// Requested passthrough constraints (separate from resolved)
345		if body["requested_harness"] != "claude" {
346			t.Errorf("requested_harness = %v, want %q", body["requested_harness"], "claude")
347		}
348		if body["requested_provider"] != "anthropic" {
349			t.Errorf("requested_provider = %v, want %q", body["requested_provider"], "anthropic")
350		}
351		if body["requested_model"] != "claude-opus-4-6" {
352			t.Errorf("requested_model = %v, want %q", body["requested_model"], "claude-opus-4-6")
353		}
354	
355		// Requested power bounds (separate from passthrough constraints)
356		if body["requested_min_power"] != float64(40) {
357			t.Errorf("requested_min_power = %v, want 40", body["requested_min_power"])
358		}
359		if body["requested_max_power"] != float64(90) {
360			t.Errorf("requested_max_power = %v, want 90", body["requested_max_power"])
361		}
362	
363		// AC3: actual_power must be a top-level numeric field so retry policy can
364		// read prior actual_power without inspecting passthrough strings (AC4).
365		if body["actual_power"] != float64(70) {
366			t.Errorf("actual_power = %v, want 70", body["actual_power"])
367		}
368	}
