370	// TestAppendBeadRoutingEvidence_ActualPowerReadableWithoutPassthrough (AC4):
371	// actual_power is a top-level numeric field in the routing evidence body,
372	// independent of the passthrough envelope strings. Retry policy can read it
373	// directly from the JSON without inspecting harness/provider/model strings.
374	func TestAppendBeadRoutingEvidence_ActualPowerReadableWithoutPassthrough(t *testing.T) {
375		app := &stubBeadEventAppenderForPassthrough{}
376		// Empty passthrough — actual_power must still be independently readable.
377		appendBeadRoutingEvidence(app, "ddx-test-02",
378			"codex", "", "gpt-4o",
379			"", "",
380			config.AgentPassthrough{}, 0, 0, 85)
381	
382		if len(app.events) != 1 {
383			t.Fatalf("expected 1 event, got %d", len(app.events))
384		}
385	
386		var body map[string]any
387		if err := json.Unmarshal([]byte(app.events[0].Body), &body); err != nil {
388			t.Fatalf("unmarshal routing body: %v", err)
389		}
390	
391		// Verify actual_power is a plain number — readable without string parsing.
392		power, ok := body["actual_power"].(float64)
393		if !ok {
394			t.Fatalf("actual_power is not a number in routing evidence: %T %v", body["actual_power"], body["actual_power"])
395		}
396		if int(power) != 85 {
397			t.Errorf("actual_power = %d, want 85", int(power))
398		}
399		// Passthrough fields are absent (empty), confirming actual_power stands alone.
400		if body["requested_harness"] != nil {
401			t.Errorf("requested_harness should be absent when passthrough is empty, got %v", body["requested_harness"])
402		}
403	}
