package agent

import (
	"fmt"

	agentlib "github.com/DocumentDrivenDX/agent"
)

// Retry policy logical outcome names. These are the policy's semantic
// vocabulary, distinct from execution status and failure-mode constants.
const (
	// RetryOutcomeSuccess marks a successful merge; no retry needed.
	RetryOutcomeSuccess = "success"

	// RetryOutcomeNoChangesAfterAttempt marks an attempt where the agent
	// produced no commits. Retryable with a higher MinPower.
	RetryOutcomeNoChangesAfterAttempt = "no_changes_after_attempt"

	// RetryOutcomeReviewBlockedCapability marks an attempt where the
	// post-merge reviewer returned BLOCK or REQUEST_CHANGES, indicating the
	// model's output did not meet the acceptance criteria. Retryable with a
	// higher MinPower.
	RetryOutcomeReviewBlockedCapability = "review_blocked_capability"

	// RetryOutcomePassthroughExhausted marks an attempt where the passthrough
	// envelope conflicts with the power bounds (blocked_by_passthrough_constraint
	// or agent_power_unsatisfied). Power escalation cannot resolve this;
	// the policy stops instead of mutating the passthrough.
	RetryOutcomePassthroughExhausted = "passthrough_exhausted"

	// RetryOutcomeSetupFailure marks a deterministic infrastructure failure that
	// power escalation cannot fix: harness not installed, no viable provider,
	// auth error, etc. The policy stops.
	RetryOutcomeSetupFailure = "deterministic_setup_failure"

	// RetryOutcomeMaxPowerNoProgress marks an attempt where MinPower cannot be
	// raised any further — either because the next threshold would exceed
	// MaxPower, or because the catalog has no higher power tier available.
	// The policy stops.
	RetryOutcomeMaxPowerNoProgress = "max_power_no_progress"

	// RetryOutcomeOther marks any outcome not eligible for power escalation.
	RetryOutcomeOther = "other"
)

// RetryDecision is the policy output for one bead attempt outcome.
// It never includes DDx-selected harness, provider, model, or model-ref pins;
// only a MinPower adjustment is returned.
type RetryDecision struct {
	// ShouldRetry indicates whether the bead should be retried with escalated
	// MinPower. false means the policy decided to stop.
	ShouldRetry bool

	// NextMinPower is the MinPower to use for the next attempt.
	// Only meaningful when ShouldRetry is true.
	NextMinPower int

	// Reason classifies why the policy decided to retry or stop.
	// Populated for both outcomes and used in audit records.
	Reason string

	// Evidence provides additional context for the audit record.
	Evidence string
}

// ClassifyRetryOutcome maps an attempt's status and failure_mode into a
// logical retry outcome that EvaluateRetryPolicy uses to make its decision.
//
// Passthrough exhaustion (blocked_by_passthrough_constraint or
// agent_power_unsatisfied) is detected first and always results in a stop,
// regardless of the status string. Deterministic setup failures (harness not
// installed, no viable provider, auth error) are detected next. All other
// classification is done from status alone.
func ClassifyRetryOutcome(status, failureMode string) string {
	// Passthrough exhaustion stops regardless of other signals; inspecting
	// the failure mode is sufficient and does not require reading string values
	// from the passthrough envelope itself.
	switch failureMode {
	case FailureModeBlockedByPassthroughConstraint, FailureModeAgentPowerUnsatisfied:
		return RetryOutcomePassthroughExhausted
	}

	// Deterministic setup failures that power escalation cannot fix.
	switch failureMode {
	case FailureModeHarnessNotInstalled, FailureModeNoViableProvider, FailureModeAuthError:
		return RetryOutcomeSetupFailure
	}

	switch status {
	case ExecuteBeadStatusSuccess, ExecuteBeadStatusAlreadySatisfied:
		return RetryOutcomeSuccess
	case ExecuteBeadStatusNoChanges:
		return RetryOutcomeNoChangesAfterAttempt
	case ExecuteBeadStatusReviewBlock, ExecuteBeadStatusReviewRequestChanges,
		ExecuteBeadStatusReviewMalfunction:
		return RetryOutcomeReviewBlockedCapability
	}

	return RetryOutcomeOther
}

// EvaluateRetryPolicy makes the retry/stop decision for one bead attempt.
//
// outcome must come from ClassifyRetryOutcome. actualPower is the power level
// used in the prior attempt (from routing evidence's actual_power field).
// currentMinPower and maxPower are the bounds currently in effect for the bead.
// models is the agent model catalog; when non-empty, top-1 (the strongest tier)
// is used as the escalation target.
//
// The returned RetryDecision never includes DDx-selected harness, provider,
// model, or model-ref pins — only a new MinPower bound. The passthrough
// envelope is neither read nor mutated.
func EvaluateRetryPolicy(
	outcome string,
	actualPower int,
	currentMinPower int,
	maxPower int,
	models []agentlib.ModelInfo,
) RetryDecision {
	switch outcome {
	case RetryOutcomeSuccess:
		return RetryDecision{
			ShouldRetry: false,
			Reason:      RetryOutcomeSuccess,
			Evidence:    "attempt succeeded; no retry needed",
		}

	case RetryOutcomePassthroughExhausted:
		return RetryDecision{
			ShouldRetry: false,
			Reason:      RetryOutcomePassthroughExhausted,
			Evidence:    "passthrough constraint or agent power bounds incompatible; retry would not resolve",
		}

	case RetryOutcomeSetupFailure:
		return RetryDecision{
			ShouldRetry: false,
			Reason:      RetryOutcomeSetupFailure,
			Evidence:    "deterministic setup failure; power escalation cannot fix",
		}

	case RetryOutcomeNoChangesAfterAttempt, RetryOutcomeReviewBlockedCapability:
		nextMinPower := computeNextMinPower(models, actualPower, currentMinPower)

		// MaxPower must be preserved across retries. If escalation would
		// produce a NextMinPower that violates the MaxPower bound, stop.
		if maxPower > 0 && nextMinPower > maxPower {
			return RetryDecision{
				ShouldRetry: false,
				Reason:      RetryOutcomeMaxPowerNoProgress,
				Evidence: fmt.Sprintf(
					"next_min_power=%d would exceed max_power=%d; cannot escalate within bounds",
					nextMinPower, maxPower),
			}
		}

		// If the computed next threshold is not higher than what was already
		// used (and not higher than currentMinPower), there is no room to
		// escalate — the catalog is exhausted.
		if nextMinPower <= actualPower && nextMinPower <= currentMinPower {
			return RetryDecision{
				ShouldRetry: false,
				Reason:      RetryOutcomeMaxPowerNoProgress,
				Evidence: fmt.Sprintf(
					"actual_power=%d; no higher power tier available in catalog",
					actualPower),
			}
		}

		return RetryDecision{
			ShouldRetry:  true,
			NextMinPower: nextMinPower,
			Reason:       outcome,
			Evidence: fmt.Sprintf(
				"actual_power=%d next_min_power=%d",
				actualPower, nextMinPower),
		}

	default:
		return RetryDecision{
			ShouldRetry: false,
			Reason:      RetryOutcomeOther,
			Evidence:    "outcome not eligible for power escalation: " + outcome,
		}
	}
}

// computeNextMinPower returns the MinPower for the next escalated attempt.
// When the models catalog is non-empty, returns TopNPowerThreshold(models, 1)
// — the minimum power required to reach only the strongest model tier.
// When the catalog is empty, bumps above the highest observed power by a
// fixed delta.
func computeNextMinPower(models []agentlib.ModelInfo, actualPower, currentMinPower int) int {
	top1 := TopNPowerThreshold(models, 1)
	if top1 > 0 {
		return top1
	}
	// No catalog: heuristic bump above the highest observed power.
	base := currentMinPower
	if actualPower > base {
		base = actualPower
	}
	if base == 0 {
		return 50
	}
	return base + 10
}

package agent

// retry_policy_test.go covers the retry policy acceptance criteria:
//   AC1: Policy reads prior attempt outcome and actual_power from evidence.
//   AC2: On retryable outcomes, NextMinPower > currentMinPower; MaxPower preserved.
//   AC3: Top-model-only MinPower threshold derived from catalog.
//   AC4: RetryDecision contains no harness/provider/model/model-ref pins.
//   AC5: Passthrough envelope is not inspected or mutated.
//   AC6: success no-retry, no_changes_after_attempt escalation,
//        review_blocked_capability escalation, passthrough-stickiness,
//        max-power/no-progress stop, deterministic setup failures stop.
//   AC7: blocked_by_passthrough_constraint and agent_power_unsatisfied stop
//        without mutating pins or calling ResolveRoute.
//   AC8: Reason and Evidence fields populated for all outcomes.

import (
	"testing"

	agentlib "github.com/DocumentDrivenDX/agent"
)

// catalogWithPowers builds a slice of ModelInfo with the given power values,
// simulating the agent model catalog returned by ListModels.
func catalogWithPowers(powers ...int) []agentlib.ModelInfo {
	models := make([]agentlib.ModelInfo, len(powers))
	for i, p := range powers {
		models[i] = agentlib.ModelInfo{
			ID:    "model-" + string(rune('A'+i)),
			Power: p,
		}
	}
	return models
}

// ── ClassifyRetryOutcome ────────────────────────────────────────────────────

func TestClassifyRetryOutcome_Success(t *testing.T) {
	got := ClassifyRetryOutcome(ExecuteBeadStatusSuccess, "")
	if got != RetryOutcomeSuccess {
		t.Errorf("status=success → %q, want %q", got, RetryOutcomeSuccess)
	}
}

func TestClassifyRetryOutcome_AlreadySatisfied(t *testing.T) {
	got := ClassifyRetryOutcome(ExecuteBeadStatusAlreadySatisfied, "")
	if got != RetryOutcomeSuccess {
		t.Errorf("status=already_satisfied → %q, want %q", got, RetryOutcomeSuccess)
	}
}

func TestClassifyRetryOutcome_NoChanges(t *testing.T) {
	got := ClassifyRetryOutcome(ExecuteBeadStatusNoChanges, FailureModeNoChanges)
	if got != RetryOutcomeNoChangesAfterAttempt {
		t.Errorf("status=no_changes → %q, want %q", got, RetryOutcomeNoChangesAfterAttempt)
	}
}

func TestClassifyRetryOutcome_ReviewBlock(t *testing.T) {
	for _, status := range []string{
		ExecuteBeadStatusReviewBlock,
		ExecuteBeadStatusReviewRequestChanges,
		ExecuteBeadStatusReviewMalfunction,
	} {
		got := ClassifyRetryOutcome(status, "")
		if got != RetryOutcomeReviewBlockedCapability {
			t.Errorf("status=%q → %q, want %q", status, got, RetryOutcomeReviewBlockedCapability)
		}
	}
}

// AC7: blocked_by_passthrough_constraint stops regardless of status.
func TestClassifyRetryOutcome_PassthroughConstraint(t *testing.T) {
	got := ClassifyRetryOutcome(ExecuteBeadStatusExecutionFailed, FailureModeBlockedByPassthroughConstraint)
	if got != RetryOutcomePassthroughExhausted {
		t.Errorf("failure_mode=blocked_by_passthrough_constraint → %q, want %q",
			got, RetryOutcomePassthroughExhausted)
	}
}

// AC7: agent_power_unsatisfied stops regardless of status.
func TestClassifyRetryOutcome_AgentPowerUnsatisfied(t *testing.T) {
	got := ClassifyRetryOutcome(ExecuteBeadStatusExecutionFailed, FailureModeAgentPowerUnsatisfied)
	if got != RetryOutcomePassthroughExhausted {
		t.Errorf("failure_mode=agent_power_unsatisfied → %q, want %q",
			got, RetryOutcomePassthroughExhausted)
	}
}

// AC6: deterministic setup failures do not retry.
func TestClassifyRetryOutcome_SetupFailures(t *testing.T) {
	cases := []string{
		FailureModeHarnessNotInstalled,
		FailureModeNoViableProvider,
		FailureModeAuthError,
	}
	for _, fm := range cases {
		got := ClassifyRetryOutcome(ExecuteBeadStatusExecutionFailed, fm)
		if got != RetryOutcomeSetupFailure {
			t.Errorf("failure_mode=%q → %q, want %q", fm, got, RetryOutcomeSetupFailure)
		}
	}
}

// Passthrough exhaustion takes priority over status classification.
func TestClassifyRetryOutcome_PassthroughPriorityOverStatus(t *testing.T) {
	// Even if the status would normally classify as no_changes, passthrough
	// exhaustion must win.
	got := ClassifyRetryOutcome(ExecuteBeadStatusNoChanges, FailureModeBlockedByPassthroughConstraint)
	if got != RetryOutcomePassthroughExhausted {
		t.Errorf("passthrough failure_mode must take priority: got %q, want %q",
			got, RetryOutcomePassthroughExhausted)
	}
}

// ── EvaluateRetryPolicy ─────────────────────────────────────────────────────

// AC6: success → no retry.
func TestEvaluateRetryPolicy_SuccessNoRetry(t *testing.T) {
	d := EvaluateRetryPolicy(RetryOutcomeSuccess, 80, 0, 0, nil)
	if d.ShouldRetry {
		t.Error("success outcome must not retry")
	}
	if d.Reason == "" {
		t.Error("Reason must be populated even for no-retry decisions (AC8)")
	}
	if d.Evidence == "" {
		t.Error("Evidence must be populated for audit records (AC8)")
	}
}

// AC6: no_changes_after_attempt → retry with escalated MinPower.
func TestEvaluateRetryPolicy_NoChangesEscalates(t *testing.T) {
	catalog := catalogWithPowers(30, 70, 100)
	d := EvaluateRetryPolicy(RetryOutcomeNoChangesAfterAttempt, 70, 0, 0, catalog)
	if !d.ShouldRetry {
		t.Fatalf("no_changes_after_attempt must retry; got ShouldRetry=false (reason=%q)", d.Reason)
	}
	// AC2: NextMinPower must be higher than currentMinPower (0).
	if d.NextMinPower <= 0 {
		t.Errorf("NextMinPower must be > 0 after escalation, got %d", d.NextMinPower)
	}
	// AC3: with catalog, must use top-1 = 100.
	if d.NextMinPower != 100 {
		t.Errorf("NextMinPower = %d, want 100 (top-1 from catalog)", d.NextMinPower)
	}
	if d.Reason == "" || d.Evidence == "" {
		t.Error("Reason and Evidence must be populated (AC8)")
	}
}

// AC6: review_blocked_capability → retry with escalated MinPower.
func TestEvaluateRetryPolicy_ReviewBlockedCapabilityEscalates(t *testing.T) {
	catalog := catalogWithPowers(40, 80, 95)
	d := EvaluateRetryPolicy(RetryOutcomeReviewBlockedCapability, 80, 0, 0, catalog)
	if !d.ShouldRetry {
		t.Fatalf("review_blocked_capability must retry; got ShouldRetry=false (reason=%q)", d.Reason)
	}
	// AC3: top-1 from catalog = 95.
	if d.NextMinPower != 95 {
		t.Errorf("NextMinPower = %d, want 95 (top-1 from catalog)", d.NextMinPower)
	}
}

// AC5, AC6: passthrough stickiness — RetryDecision has no harness/provider/model/
// model-ref fields. Verified structurally: RetryDecision only exposes power bounds.
func TestEvaluateRetryPolicy_DecisionContainsNoPins(t *testing.T) {
	catalog := catalogWithPowers(50, 90)
	d := EvaluateRetryPolicy(RetryOutcomeNoChangesAfterAttempt, 50, 0, 0, catalog)
	if !d.ShouldRetry {
		t.Fatalf("expected retry, got stop (reason=%q)", d.Reason)
	}
	// RetryDecision struct: only ShouldRetry, NextMinPower, Reason, Evidence.
	// AC4: no harness/provider/model/model-ref fields exist on this type.
	// The test verifies this at compile-time: assigning those fields would be
	// a compile error. We confirm only the expected fields are used.
	_ = d.ShouldRetry
	_ = d.NextMinPower
	_ = d.Reason
	_ = d.Evidence
}

// AC2: MaxPower is preserved — NextMinPower must not exceed MaxPower.
func TestEvaluateRetryPolicy_MaxPowerPreserved(t *testing.T) {
	catalog := catalogWithPowers(50, 80, 100)
	// MaxPower=90 limits escalation; top-1 (100) would exceed it.
	d := EvaluateRetryPolicy(RetryOutcomeNoChangesAfterAttempt, 50, 0, 90, catalog)
	if d.ShouldRetry {
		t.Errorf("top-1=100 > max_power=90: must stop, got ShouldRetry=true NextMinPower=%d", d.NextMinPower)
	}
	if d.Reason != RetryOutcomeMaxPowerNoProgress {
		t.Errorf("Reason = %q, want %q", d.Reason, RetryOutcomeMaxPowerNoProgress)
	}
}

// AC6: max-power/no-progress stop when catalog is exhausted.
func TestEvaluateRetryPolicy_NoCatalogNoProgress(t *testing.T) {
	// actual_power and currentMinPower both at same level; no catalog to go higher.
	// The heuristic bump will give base+10=80; since actualPower=70 and nextMinPower=80 > actualPower,
	// this should still retry. But if actualPower matches nextMinPower exactly...
	//
	// Test the specific "catalog exhausted" case: when top-1 is not available
	// and heuristic bump still produces something higher, we retry.
	// When top-1 <= actualPower, we stop.
	catalog := catalogWithPowers(50) // top-1 = 50; actualPower = 70 (already above top-1)
	d := EvaluateRetryPolicy(RetryOutcomeNoChangesAfterAttempt, 70, 0, 0, catalog)
	if d.ShouldRetry {
		t.Errorf("top-1=50 <= actual_power=70: no escalation possible, got ShouldRetry=true NextMinPower=%d", d.NextMinPower)
	}
	if d.Reason != RetryOutcomeMaxPowerNoProgress {
		t.Errorf("Reason = %q, want %q", d.Reason, RetryOutcomeMaxPowerNoProgress)
	}
}

// AC6: max-power/no-progress when actualPower is already at currentMinPower
