		d := EvaluateRetryPolicy(outcome, 80, 0, 0, catalog)
		if d.ShouldRetry {
			t.Errorf("failure_mode=%q: must stop, got ShouldRetry=true", fm)
		}
		if d.Reason != RetryOutcomeSetupFailure {
